// ==============================
// EMI CALCULATOR
// ==============================
var emiState=null;
function round2(n){return Math.round((n+Number.EPSILON)*100)/100;}
function calculateEMI(){
var loan=parseFloat(document.getElementById('emiLoanAmount').value)||0;
var annualRate=parseFloat(document.getElementById('emiAnnualRate').value)||0;
var tenor=parseFloat(document.getElementById('emiTenor').value)||0;
var tenorUnit=document.getElementById('emiTenorUnit').value;
var rateType=document.getElementById('emiRateType').value;
var result=document.getElementById('emiResult');
if(loan<=0||tenor<=0){result.className='result-box applicable';result.innerHTML='<div class="result-title">Please enter loan amount and installment tenor.</div>';return;}
if(annualRate<0){result.className='result-box applicable';result.innerHTML='<div class="result-title">Annual interest rate cannot be negative.</div>';return;}
var months=Math.round(tenorUnit==='years'?tenor*12:tenor);
if(months<=0){result.className='result-box applicable';result.innerHTML='<div class="result-title">Installment tenor must be at least 1 month.</div>';return;}
var monthlyRate=annualRate/12/100;
var schedule=[];
var emi=0,totalInterest=0,totalPayment=0,balance=loan;
if(rateType==='reducing'){
emi=monthlyRate===0?loan/months:(loan*monthlyRate*Math.pow(1+monthlyRate,months))/(Math.pow(1+monthlyRate,months)-1);
for(var i=1;i<=months;i++){
var opening=balance;
var interest=monthlyRate===0?0:opening*monthlyRate;
var principal=emi-interest;
if(i===months){principal=opening;emi=principal+interest;}
balance=Math.max(0,opening-principal);
interest=round2(interest);principal=round2(principal);emi=round2(emi);balance=round2(balance);
totalInterest+=interest;totalPayment+=emi;
schedule.push({no:i,opening:round2(opening),emi:emi,interest:interest,principal:principal,closing:balance});
}
}else{
var flatInterest=loan*(annualRate/100)*(months/12);
emi=(loan+flatInterest)/months;
var fixedInterest=flatInterest/months;
var principalPart=loan/months;
for(var j=1;j<=months;j++){
var openBal=balance;
var principalFlat=j===months?openBal:principalPart;
var interestFlat=annualRate===0?0:fixedInterest;
var emiFlat=principalFlat+interestFlat;
balance=Math.max(0,openBal-principalFlat);
interestFlat=round2(interestFlat);principalFlat=round2(principalFlat);emiFlat=round2(emiFlat);balance=round2(balance);
totalInterest+=interestFlat;totalPayment+=emiFlat;
schedule.push({no:j,opening:round2(openBal),emi:emiFlat,interest:interestFlat,principal:principalFlat,closing:balance});
}
emi=schedule.length?schedule[0].emi:0;
}
totalInterest=round2(totalInterest);
totalPayment=round2(totalPayment);
emiState={loan:round2(loan),annualRate:annualRate,months:months,tenor:tenor,tenorUnit:tenorUnit,rateType:rateType,emi:round2(emi),totalInterest:totalInterest,totalPayment:totalPayment,schedule:schedule};
result.className='result-box presumptive';
result.innerHTML='<div class="result-title">EMI Schedule Generated</div>'+
'<div class="stats-row" style="margin-top:14px;">'+
'<div class="stat-card"><div class="stat-number">Rs '+fmt(emiState.emi)+'</div><div class="stat-label">Monthly EMI</div></div>'+
'<div class="stat-card"><div class="stat-number">Rs '+fmt(emiState.totalInterest)+'</div><div class="stat-label">Total Interest</div></div>'+
'<div class="stat-card"><div class="stat-number">Rs '+fmt(emiState.totalPayment)+'</div><div class="stat-label">Total Payment</div></div>'+
'<div class="stat-card"><div class="stat-number">'+fmt(emiState.months)+'</div><div class="stat-label">Installments</div></div>'+
'</div>'+
'<div class="result-detail"><p><strong>Rate Type:</strong> '+(rateType==='reducing'?'Reducing Balance':'Fixed / Flat Rate')+' | <strong>Loan Amount:</strong> Rs '+fmt(emiState.loan)+' | <strong>Annual Interest:</strong> '+annualRate+'%</p>'+
'<div class="table-scroll"><table class="limits-table"><thead><tr><th>No.</th><th>Opening Balance</th><th>EMI</th><th>Interest</th><th>Principal</th><th>Closing Balance</th></tr></thead><tbody>'+
schedule.map(function(row){return '<tr><td>'+row.no+'</td><td>Rs '+fmt(row.opening)+'</td><td>Rs '+fmt(row.emi)+'</td><td>Rs '+fmt(row.interest)+'</td><td>Rs '+fmt(row.principal)+'</td><td>Rs '+fmt(row.closing)+'</td></tr>';}).join('')+
'</tbody></table></div></div>';
}
function resetEMI(){
['emiLoanAmount','emiAnnualRate','emiTenor'].forEach(function(id){document.getElementById(id).value='';});
document.getElementById('emiTenorUnit').value='years';
document.getElementById('emiRateType').value='reducing';
document.getElementById('emiResult').className='result-box';
document.getElementById('emiResult').innerHTML='';
emiState=null;
}
function downloadEMIPDF(){
if(!emiState){alert('Generate the EMI schedule first.');return;}
if(!window.jspdf||!window.jspdf.jsPDF){alert('PDF library could not be loaded. Please check your internet connection and try again.');return;}
var jsPDF=window.jspdf.jsPDF;
var doc=new jsPDF({orientation:'landscape',unit:'pt',format:'a4'});
doc.setFontSize(16);
doc.text('EMI Schedule',40,40);
doc.setFontSize(10);
doc.text('Loan Amount: Rs '+fmt(emiState.loan),40,65);
doc.text('Annual Interest Rate: '+emiState.annualRate+'%',220,65);
doc.text('Rate Type: '+(emiState.rateType==='reducing'?'Reducing Balance':'Fixed / Flat Rate'),420,65);
doc.text('Installments: '+emiState.months,40,82);
doc.text('Monthly EMI: Rs '+fmt(emiState.emi),220,82);
doc.text('Total Interest: Rs '+fmt(emiState.totalInterest),420,82);
doc.text('Total Payment: Rs '+fmt(emiState.totalPayment),620,82);
if(doc.autoTable){
doc.autoTable({
startY:100,
head:[['No.','Opening Balance','EMI','Interest','Principal','Closing Balance']],
body:emiState.schedule.map(function(row){return [String(row.no),'Rs '+fmt(row.opening),'Rs '+fmt(row.emi),'Rs '+fmt(row.interest),'Rs '+fmt(row.principal),'Rs '+fmt(row.closing)];}),
styles:{fontSize:8,cellPadding:4},
headStyles:{fillColor:[32,58,67]},
alternateRowStyles:{fillColor:[248,255,254]},
margin:{left:30,right:30}
});
}
doc.save('emi-schedule.pdf');
}

