function updateDepRate(){var v=document.getElementById('depAsset').value,inp=document.getElementById('depRate');if(v&&v!=='custom'){inp.value=parseInt(v);}}
function calcDep(){var rate=parseFloat(document.getElementById('depRate').value)||0,wdv=parseFloat(document.getElementById('depWDV').value)||0,add=parseFloat(document.getElementById('depAdd').value)||0,del=parseFloat(document.getElementById('depDel').value)||0,half=document.getElementById('dep180').value,r=document.getElementById('depResult');
if(!rate||(!wdv&&!add)){r.className='result-box applicable';r.innerHTML='<div class="result-title">Enter asset details</div>';return;}
var base=wdv+add-del;if(base<0)base=0;
var effectiveRate=half==='no'?rate/2:rate;
var dep=Math.round(base*effectiveRate/100);var closing=base-dep;
r.className='result-box presumptive';
r.innerHTML='<div class="result-title">Depreciation: '+fmt(dep)+'</div><div class="result-detail"><table class="limits-table" style="margin-top:10px;"><tr><th>Particulars</th><th>Amount</th></tr><tr><td>Opening WDV</td><td>'+fmt(wdv)+'</td></tr><tr><td>(+) Additions</td><td>'+fmt(add)+'</td></tr><tr><td>(-) Deletions/Sale</td><td>'+fmt(del)+'</td></tr><tr><td>Base for Depreciation</td><td><strong>'+fmt(base)+'</strong></td></tr><tr><td>Rate Applied</td><td>'+effectiveRate+'%'+(half==='no'?' (50% of '+rate+'%)':'')+'</td></tr><tr style="background:#e8f8f5;"><td><strong>Depreciation</strong></td><td><strong>'+fmt(dep)+'</strong></td></tr><tr><td><strong>Closing WDV</strong></td><td><strong>'+fmt(closing)+'</strong></td></tr></table></div>';}
function resetDep(){['depRate','depWDV','depAdd','depDel'].forEach(function(id){document.getElementById(id).value='';});document.getElementById('depAsset').value='';document.getElementById('depResult').className='result-box';}

