// SMART SEARCH (Cross-reference)

// ==================== IT REFUND & 244A JS ====================
function calcRefund(){
var tds=parseFloat(document.getElementById('rfTDS').value)||0;
var advTax=parseFloat(document.getElementById('rfAdvTax').value)||0;
var sat=parseFloat(document.getElementById('rfSAT').value)||0;
var taxDue=parseFloat(document.getElementById('rfTaxDue').value)||0;
var timely=document.getElementById('rfTimely').value;
var dueType=document.getElementById('rfDueType').value;
var fileDateStr=document.getElementById('rfFileDate').value;
var refundDateStr=document.getElementById('rfRefundDate').value;
var ay=document.getElementById('rfAY').value;
var r=document.getElementById('rfResult');
var totalPaid=tds+advTax+sat;
if(totalPaid<=0&&taxDue<=0){r.className='result-box applicable';r.innerHTML='<div class="result-title">Please enter tax details.</div>';return;}
var refundAmt=totalPaid-taxDue;
if(refundAmt<=0){r.className='result-box applicable';r.innerHTML='<div class="result-title" style="color:#d63031;">No Refund Due</div><div class="result-detail">Total tax paid (Rs '+fmt(totalPaid)+') is less than or equal to tax determined (Rs '+fmt(taxDue)+'). You owe Rs '+fmt(Math.abs(refundAmt))+' to the department.</div>';return;}
var refundTDSAdv=Math.max(0,tds+advTax-taxDue);
var refundSAT=Math.max(0,refundAmt-refundTDSAdv);
var ayYear=parseInt(ay.split('-')[0]);
var aprStart=new Date(ayYear,3,1);
var dueDate;
if(dueType==='july')dueDate=new Date(ayYear,6,31);
else if(dueType==='october')dueDate=new Date(ayYear,9,31);
else dueDate=new Date(ayYear,10,30);
var fileDate=fileDateStr?new Date(fileDateStr):new Date();
var refundDate=refundDateStr?new Date(refundDateStr):new Date();
var interestStart;
if(timely==='yes'){interestStart=aprStart;}else{interestStart=fileDate;}
var diffMs=refundDate.getTime()-interestStart.getTime();
var months=Math.ceil(diffMs/(1000*60*60*24*30.44));
if(months<0)months=0;
var noInterest=(refundAmt<100)||(refundAmt<=(taxDue*0.1));
var interest244A=0;
if(!noInterest&&refundTDSAdv>0){interest244A=Math.round(refundTDSAdv*0.005*months);}
var satInterest=0;
r.className='result-box presumptive';
var html='<div class="result-title">Refund & Section 244A Interest Computation</div><div class="result-detail">';
html+='<h3 style="margin:10px 0 6px;color:var(--accent);">Step A — Refund Amount</h3>';
html+='<table class="limits-table"><tr><td>TDS</td><td>Rs '+fmt(tds)+'</td></tr>';
html+='<tr><td>Advance Tax</td><td>Rs '+fmt(advTax)+'</td></tr>';
html+='<tr><td>Self Assessment Tax</td><td>Rs '+fmt(sat)+'</td></tr>';
html+='<tr><td><strong>Total Tax Paid</strong></td><td><strong>Rs '+fmt(totalPaid)+'</strong></td></tr>';
html+='<tr><td>Tax Determined on Assessment</td><td>Rs '+fmt(taxDue)+'</td></tr>';
html+='<tr style="background:#e8f8f5;"><td><strong>Refund Due</strong></td><td><strong>Rs '+fmt(refundAmt)+'</strong></td></tr>';
if(noInterest){html+='<tr style="background:#fef9e7;"><td colspan="2"><strong>No interest u/s 244A payable</strong> — Refund '+(refundAmt<100?'is less than Rs 100':'is ≤ 10% of tax determined')+'</td></tr>';}
html+='</table>';
if(!noInterest){
html+='<h3 style="margin:14px 0 6px;color:var(--accent);">Step B — Section 244A Interest</h3>';
html+='<table class="limits-table"><tr><td>Refund out of TDS + Advance Tax</td><td>Rs '+fmt(refundTDSAdv)+'</td></tr>';
html+='<tr><td>Interest period</td><td>'+interestStart.toLocaleDateString('en-IN',{day:'2-digit',month:'short',year:'numeric'})+' to '+refundDate.toLocaleDateString('en-IN',{day:'2-digit',month:'short',year:'numeric'})+'</td></tr>';
html+='<tr><td>Months</td><td>'+months+'</td></tr>';
html+='<tr style="background:#e8f8f5;"><td><strong>Interest @ 6% p.a. (0.5%/month)</strong></td><td><strong>Rs '+fmt(interest244A)+'</strong></td></tr></table>';
}
html+='<h3 style="margin:14px 0 6px;color:var(--accent);">Total</h3>';
html+='<table class="limits-table"><tr style="background:#dfe6e9;font-weight:700;font-size:1.05rem;"><td>Total Refund + Interest</td><td>Rs '+fmt(refundAmt+interest244A)+'</td></tr></table>';
html+='<p style="margin-top:10px;font-size:0.82rem;color:#666;">Interest u/s 244A is taxable as Income from Other Sources in the year of receipt.</p></div>';
r.innerHTML=html;
}
function resetRefund(){['rfTDS','rfAdvTax','rfSAT','rfTaxDue','rfFileDate','rfRefundDate'].forEach(function(id){document.getElementById(id).value='';});document.getElementById('rfTimely').value='yes';document.getElementById('rfResult').className='result-box';document.getElementById('rfResult').innerHTML='';}


